window.docContents[153].resolve({"/Elliptic-Curves-and-Arithmetic-Geometry/Forthcoming-in-mathlib/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Elliptic-Curves-and-Arithmetic-Geometry--Forthcoming-in-mathlib--The-Northcott-Property":{"contents":"(Northcott property.) Equip the algebraic numbers with the absolute Weil height . For\nevery pair of real bounds  and , the set\n\nis finite; in particular a number field () has only finitely many\nelements of bounded height.This finiteness is the engine behind the Mordell–Weil theorem and the finiteness of\nbounded-height rational points on an elliptic curve ().\nPR #39744 establishes the Northcott property for the height on number fields.\nIn review — mathlib PR #39744.\n\n","context":"AINTLIB — An Atlas of Number Theory in Lean\u0009Elliptic Curves and Arithmetic Geometry\u0009Forthcoming in mathlib","header":"7.13.3. The Northcott Property","id":"/Elliptic-Curves-and-Arithmetic-Geometry/Forthcoming-in-mathlib/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Elliptic-Curves-and-Arithmetic-Geometry--Forthcoming-in-mathlib--The-Northcott-Property"}});